import os

def delete_uploaded_file(filename):
    filepath = os.path.join('uploads', filename)
    if not os.path.exists(filepath):
        return False
    try:
        os.remove(filepath)
    except OSError as e:
        print(f"Error deleting file {filename}: {e}")
        return False
    return True